    function data_matrix_operations($matrix_a, $operation, $matrix_b = null, $scalar = null)
    {
        if (!is_array($matrix_a) || empty($matrix_a)) {
            return json_encode(['error' => 'matrix_a must be a non-empty 2D array']);
        }

        // Validate matrix_a dimensions
        $rowsA = count($matrix_a);
        $colsA = count($matrix_a[0]);
        foreach ($matrix_a as $i => $row) {
            if (!is_array($row) || count($row) !== $colsA) {
