                    $row[] = $matrix_a[$r][$c];
                }
                $result[] = $row;
            }
            $label = "Transpose of {$rowsA}x{$colsA} matrix";
        } elseif ($op === 'determinant') {
            if ($rowsA !== $colsA || ($rowsA !== 2 && $rowsA !== 3)) {
                return json_encode(['error' => 'Determinant only supported for 2x2 and 3x3 matrices']);
            }
            if ($rowsA === 2) {
                $det = $matrix_a[0][0] * $matrix_a[1][1] - $matrix_a[0][1] * $matrix_a[1][0];
            } else {
                // 3x3 using Sarrus' rule
                $det = $matrix_a[0][0] * $matrix_a[1][1] * $matrix_a[2][2]
                     + $matrix_a[0][1] * $matrix_a[1][2] * $matrix_a[2][0]
                     + $matrix_a[0][2] * $matrix_a[1][0] * $matrix_a[2][1]
                     - $matrix_a[0][2] * $matrix_a[1][1] * $matrix_a[2][0]
                     - $matrix_a[0][0] * $matrix_a[1][2] * $matrix_a[2][1]
                     - $matrix_a[0][1] * $matrix_a[1][0] * $matrix_a[2][2];
            }
            return json_encode([
                'operation' => 'determinant',
                'matrix_size' => "{$rowsA}x{$colsA}",
