                }
            }

            if ($op === 'add' || $op === 'subtract') {
                if ($rowsA !== $rowsB || $colsA !== $colsB) {
                    return json_encode(['error' => "Matrix dimensions must match for $op: A is {$rowsA}x{$colsA}, B is {$rowsB}x{$colsB}"]);
                }
                $result = [];
                for ($r = 0; $r < $rowsA; $r++) {
                    $newRow = [];
                    for ($c = 0; $c < $colsA; $c++) {
                        $newRow[] = $op === 'add'
                            ? round($matrix_a[$r][$c] + $matrix_b[$r][$c], 10)
                            : round($matrix_a[$r][$c] - $matrix_b[$r][$c], 10);
                    }
                    $result[] = $newRow;
                }
                $label = "A {$op} B";
            } elseif ($op === 'multiply') {
