                $result = [];
                for ($r = 0; $r < $rowsA; $r++) {
                    $newRow = [];
                    for ($c = 0; $c < $colsB; $c++) {
                        $sum = 0;
                        for ($k = 0; $k < $colsA; $k++) {
                            $sum += $matrix_a[$r][$k] * $matrix_b[$k][$c];
                        }
                        $newRow[] = round($sum, 10);
                    }
                    $result[] = $newRow;
                }
                $label = "A * B (matrix product)";
            } else {
                return json_encode(['error' => "Unknown operation: '$op'"]);
            }
        }

        return json_encode([
            'operation' => $op,
            'label' => $label,
